import{_ as l,o as t,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"1977年巴菲特致股东的信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1977年/核心总结.md","filePath":"01_letters/1977年/核心总结.md"}'),o={name:"01_letters/1977年/核心总结.md"};function e(n,a,s,h,u,d){return t(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="_1977年巴菲特致股东的信核心总结" tabindex="-1">1977年巴菲特致股东的信核心总结 <a class="header-anchor" href="#_1977年巴菲特致股东的信核心总结" aria-label="Permalink to &quot;1977年巴菲特致股东的信核心总结&quot;">​</a></h1><h2 id="简要导读" tabindex="-1">简要导读 <a class="header-anchor" href="#简要导读" aria-label="Permalink to &quot;简要导读&quot;">​</a></h2><p>1977年是巴菲特掌管伯克希尔的第13个年头，此时的伯克希尔还是一个横跨纺织、保险、银行的多元化集团，还没有进化为后来纯粹的投资控股公司。这封信虽然不长，但已经清晰展现了巴菲特中后期投资体系的核心骨架：如何衡量管理层表现、如何看待商业模式、如何选择股票，许多观点放到今天依然振聋发聩。文末可下载英文原版PDF。</p><h2 id="一、整体业绩与衡量标准" tabindex="-1">一、整体业绩与衡量标准 <a class="header-anchor" href="#一、整体业绩与衡量标准" aria-label="Permalink to &quot;一、整体业绩与衡量标准&quot;">​</a></h2><ul><li>1977年营业利润2190.4万美元，每股收益22.54美元，好于预期，期初股本回报率19%，高于美国工业平均水平。</li><li><strong>核心观点</strong>：大多数公司把每股收益创新高叫做&quot;创纪录&quot;，但由于股本每年都会增长，这种增长其实水分很大。就像储蓄账户靠复利自然也会每年增加利息。巴菲特认为<strong>衡量管理业绩更合适的指标是股本回报率</strong>，而非每股收益增长。</li></ul><h2 id="二、各业务板块表现" tabindex="-1">二、各业务板块表现 <a class="header-anchor" href="#二、各业务板块表现" aria-label="Permalink to &quot;二、各业务板块表现&quot;">​</a></h2><h3 id="_1-纺织业务-继续低迷-但为何不退出" tabindex="-1">1. 纺织业务：继续低迷，但为何不退出？ <a class="header-anchor" href="#_1-纺织业务-继续低迷-但为何不退出" aria-label="Permalink to &quot;1. 纺织业务：继续低迷，但为何不退出？&quot;">​</a></h3><ul><li>连续多年表现差，远低于预期，长期回报率不可能比得上其他行业。</li><li>巴菲特给出三个继续坚持的理由： <ol><li>是当地最大雇主，工人年龄大、技能难转移，工人和工会一直积极配合，不愿裁员关厂</li><li>纺织业务早年为伯克希尔扩张保险业务提供了收购资金，有历史恩情</li><li>依然有可能通过努力调整，实现适度盈利</li></ol></li></ul><h3 id="_2-保险业务-大获成功-但周期拐点临近" tabindex="-1">2. 保险业务：大获成功，但周期拐点临近 <a class="header-anchor" href="#_2-保险业务-大获成功-但周期拐点临近" aria-label="Permalink to &quot;2. 保险业务：大获成功，但周期拐点临近&quot;">​</a></h3><ul><li>从1967年860万美元收购，到1977年总保费1.51亿美元，增长近600%，全程没有增发新股。</li><li>1977年是保险承保的顺风年，1974-1975年行业灾难后，1976年涨价，1977年才完全体现到利润，表现远超预期。</li><li><strong>关键判断</strong>：通胀加上社会不断扩大保障范围，成本每月上涨约1%，最近涨价速度已经放缓，预计下半年承保利润率会开始下降。</li><li><strong>最重要的教训</strong>：待在<strong>顺风的行业</strong>比逆风强。保险行业哪怕犯点错，整体依然能获得不错结果；而纺织行业，哪怕最优秀的管理层也只能获得平庸回报。</li><li>值得注意：保险行业高度依赖优秀管理者，人的因素被放大，伯克希尔当时非常幸运拥有一流管理团队。</li></ul><h3 id="_3-投资理念阐述" tabindex="-1">3. 投资理念阐述 <a class="header-anchor" href="#_3-投资理念阐述" aria-label="Permalink to &quot;3. 投资理念阐述&quot;">​</a></h3><ul><li>过去两年保险投资从1.35亿增长到2.53亿美元，未实现利得约7400万美元，但巴菲特强调：不必太在意单日股价，我们长期持有，<strong>记分牌是企业长期经营结果，不是短期股价</strong>。</li><li><strong>选股标准（核心中的核心）</strong>：我们买股票和买整个企业的标准一样： <ol><li>我们能理解</li><li>有良好长期前景</li><li>由诚实能干的人运营</li><li>价格非常有吸引力</li></ol></li><li><strong>心态</strong>：我们不为短期股价买股票，如果企业好，我们甚至欢迎股价下跌，这样能以更便宜价格买更多。</li><li><strong>有趣的洞见</strong>：杰出企业的少数股权，在股市上往往比直接收购整家公司便宜得多，这是二级市场持股的优势。我们喜欢大仓位，但不想要控制权，现有管理层已经很棒，<strong>不控股反而能得到更好的管理结果</strong>。</li><li>持仓举例：1977年新进首都城市通信，重仓华盛顿邮报、GEICO等，都是经典的长期投资案例。</li></ul><h3 id="_4-银行业-持续优异" tabindex="-1">4. 银行业：持续优异 <a class="header-anchor" href="#_4-银行业-持续优异" aria-label="Permalink to &quot;4. 银行业：持续优异&quot;">​</a></h3><ul><li>伊利诺伊国民银行资产收益率是大银行三倍，保持高息、低风险、高流动性。创始人吉恩·阿贝格80岁交棒，但依然担任董事长，业绩一直非常出色。</li></ul><h3 id="_5-蓝筹印花-喜诗糖果的惊喜" tabindex="-1">5. 蓝筹印花：喜诗糖果的惊喜 <a class="header-anchor" href="#_5-蓝筹印花-喜诗糖果的惊喜" aria-label="Permalink to &quot;5. 蓝筹印花：喜诗糖果的惊喜&quot;">​</a></h3><ul><li>伯克希尔持股36.5%，蓝筹旗下喜诗糖果从1972年收购至今，税前利润从420万涨到1260万，几乎没有增加资本投入，在行业零增长环境下取得这样的成绩非常难得。这后来成为巴菲特最成功的投资之一。</li></ul><h2 id="三、核心启示" tabindex="-1">三、核心启示 <a class="header-anchor" href="#三、核心启示" aria-label="Permalink to &quot;三、核心启示&quot;">​</a></h2><ol><li><strong>正确衡量业绩</strong>：别被每股收益增长迷惑，要看股本回报率。</li><li><strong>商业模式&gt;管理</strong>：再好的管理也救不了逆风行业，&quot;选择顺风的行业&quot;是最重要的决策。</li><li><strong>买股票就是买企业</strong>：选股标准和收购整家公司一样，看得是长期生意，不是短期股价。</li><li><strong>厚道与责任</strong>：面对亏损的纺织业务，考虑员工利益不轻易关厂，体现了巴菲特早期就有的经营责任感。</li></ol><hr><blockquote><p>📎 <strong>文末小惊喜</strong>：可点击下载<a href="./Chairman&#39;s%20Letter%20-%201977.pdf">巴菲特1977年股东信原件PDF</a>，原汁原味阅读英文原文。</p></blockquote>',20)])])}const g=l(o,[["render",e]]);export{c as __pageData,g as default};
